import { z } from "npm:zod@^3.25.76";
function matches(v, q) {
  if (!q) return true;
  const hay = [
    v.name,
    v.make,
    v.model,
    v.year?.toString(),
    v.exteriorColor,
    v.fuel,
    v.transmission,
    v.vin,
    v.stockNumber
  ].filter(Boolean).join(" ").toLowerCase();
  return q.toLowerCase().split(/\s+/).filter(Boolean).every((tok) => hay.includes(tok));
}
