import { defineTool as defineTool3 } from "npm:@lovable.dev/mcp-js@0.20.1";
import { createClient } from "npm:@supabase/supabase-js@^2.86.0";
import { z as z3 } from "npm:zod@^3.25.76";
function supabaseForUser(token) {
  const env = globalThis.process?.env ?? {};
  const url = env.SUPABASE_URL;
  const anon = env.SUPABASE_PUBLISHABLE_KEY ?? env.SUPABASE_ANON_KEY ?? "";
  return createClient(url, anon, {
    global: { headers: { Authorization: `Bearer ${token}` } },
    auth: { persistSession: false, autoRefreshToken: false }
  });
}
var list_recent_leads_default = defineTool3({
  name: "list_recent_leads",
  title: "List recent Middleman Motors leads",
  description: "Return the most recent customer leads. Admin/finance access only. Sensitive customer data \u2014 do not share externally.",
  inputSchema: {
    limit: z3.number().int().min(1).max(50).default(10).describe("Max leads to return (1-50)."),
    status: z3.string().optional().describe("Optional status filter (e.g. 'new', 'contacted').")
  },
  annotations: { readOnlyHint: true, idempotentHint: true, openWorldHint: false },
  handler: async ({ limit, status }, ctx) => {
    if (!ctx.isAuthenticated()) {
      return { content: [{ type: "text", text: "Not authenticated." }], isError: true };
    }
    const sb = supabaseForUser(ctx.getToken());
    let q = sb.from("leads").select("id, created_at, name, email, phone, source, program_tags, status, message").order("created_at", { ascending: false }).limit(limit);
    if (status) q = q.eq("status", status);
    const { data, error } = await q;
    if (error) {
      return {
        content: [{ type: "text", text: `Query failed: ${error.message}` }],
        isError: true
      };
    }
    if (!data || data.length === 0) {
      return { content: [{ type: "text", text: "No leads found." }], structuredContent: { leads: [] } };
    }
    const lines = data.map(
      (l) => `\u2022 ${l.name ?? "\u2014"} <${l.email ?? "no email"}> \xB7 ${l.phone ?? "no phone"} \xB7 ${l.source ?? "?"} \xB7 ${l.status ?? "new"} \xB7 ${new Date(l.created_at).toLocaleDateString()}`
    );
    return {
      content: [{ type: "text", text: `${data.length} recent leads:
${lines.join("\n")}` }],
      structuredContent: { leads: data }
    };
  }
});

